// weekdayFullName maps a short weekday header to its full name for a11y labels.
func weekdayFullName(short string) string {
	switch short {
	case "Su":
		return "Sunday"
	case "Mo":
		return "Monday"
	case "Tu":
		return "Tuesday"
	case "We":
		return "Wednesday"
	case "Th":
		return "Thursday"
	case "Fr":
		return "Friday"
	case "Sa":
		return "Saturday"
	}
	return short
}

